const fs = require('fs');
const input = $input.first().json;
const body = input.body || input;
const type = String(body.type || 'board');
const sageDir = '/data/Aidan_Outputs/Sage/';

// Board recipients from KAI_Context.json
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }

const boardMembers = ctx.eaf_board && ctx.eaf_board.members ? ctx.eaf_board.members : [
  { name: 'James L. Scott, Esq.', email: 'jlslaw@yahoo.com' },
  { name: 'Keith Millard', email: 'keithrmillard@gmail.com' },
  { name: 'Maurice Ellis', email: 'bjet.1234@yahoo.com' }
];

const month = new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric', timeZone: 'America/New_York' });

let draftPath = null;
let draftContent = '';
let subject = '';
let recipients = [];

if (type === 'board') {
  const files = fs.readdirSync(sageDir).filter(function(f) { return f.startsWith('Board_Newsletter') && f.endsWith('.txt'); }).sort().reverse();
  if (files.length === 0) {
    return [{ json: { error: true, message: 'No board newsletter draft found. Say Sage board to generate one first.' } }];
  }
  draftPath = sageDir + files[0];
  draftContent = fs.readFileSync(draftPath, 'utf8');
  subject = 'EAF Board Newsletter — ' + month;
  recipients = boardMembers.map(function(m) { return { name: m.name, email: m.email }; });

} else if (type === 'market') {
  const files = fs.readdirSync(sageDir).filter(function(f) { return f.startsWith('Market_Newsletter') && f.endsWith('.txt'); }).sort().reverse();
  if (files.length === 0) {
    return [{ json: { error: true, message: 'No market newsletter draft found. Say Sage market to generate one first.' } }];
  }
  draftPath = sageDir + files[0];
  draftContent = fs.readFileSync(draftPath, 'utf8');
  subject = 'KAI-Netics Update — ' + month;
  // Market recipients — BD pipeline contacts
  // For now send to Kevin + board for review — expand list as BD pipeline grows
  recipients = [
    { name: 'Kevin Alexander Smith', email: 'kas@kevin-llc.com' },
    { name: 'James L. Scott, Esq.', email: 'jlslaw@yahoo.com' },
    { name: 'Keith Millard', email: 'keithrmillard@gmail.com' },
    { name: 'Maurice Ellis', email: 'bjet.1234@yahoo.com' }
  ];
}

// Build branded HTML email
const safeContent = draftContent.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

let headerColor = type === 'board' ? '#1a1a2e' : '#0a3d62';
let headerLabel = type === 'board' ? 'EAF Board Newsletter' : 'KAI-Netics Market Update';
let entityLine = type === 'board' ? 'KAI-Netics Equity &amp; Autonomy Foundry, Inc. | EIN: 41-4820296' : 'Kevin Alexander International LLC dba KAI-Netics';

const htmlBody = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto">' +
  '<div style="background:' + headerColor + ';padding:24px;border-radius:8px 8px 0 0">' +
  '<h1 style="color:#00d4ff;margin:0;font-size:20px">KAI-Netics</h1>' +
  '<p style="color:#8888aa;margin:4px 0 0 0;font-size:13px">' + headerLabel + ' | ' + month + '</p>' +
  '</div>' +
  '<div style="background:#ffffff;padding:28px;border:1px solid #e0e0e0">' +
  '<p style="color:#555;font-size:12px;margin:0 0 16px 0">' + entityLine + '</p>' +
  '<div style="white-space:pre-wrap;font-size:14px;line-height:1.7;color:#222;font-family:Arial,sans-serif">' + safeContent + '</div>' +
  '</div>' +
  '<div style="background:' + headerColor + ';padding:16px;border-radius:0 0 8px 8px;text-align:center">' +
  '<p style="color:#8888aa;margin:0;font-size:12px">Kevin Alexander Smith | KAI-Netics | kas@kevin-llc.com | 443.257.6836</p>' +
  '<p style="color:#8888aa;margin:4px 0 0 0;font-size:11px">FAA Part 107 Certified | MEIA Phase 2 Cohort | MWVOB</p>' +
  '</div></div>';

return [{ json: {
  type: type,
  subject: subject,
  htmlBody: htmlBody,
  draftPath: draftPath,
  recipients: recipients,
  month: month,
  recipientCount: recipients.length
}}];

const fs = require('fs');
const http = require('http');
const input = $input.first().json;

if (input.error) {
  const errMsg = 'SAGE SEND ERROR: ' + input.message;
  const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: errMsg } });
  const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
  await new Promise(function(r) { const req = http.request(opts, function(res) { res.on('data',function(){}); res.on('end',r); }); req.on('error',r); req.write(msgBody); req.end(); });
  return [{ json: { success: false, error: input.message } }];
}

// Log the send
const logPath = '/data/Aidan_Outputs/Sage/' + (input.type === 'board' ? 'BOARD' : 'MARKET') + '_SENT_' + new Date().toISOString().replace(/[:.]/g,'-') + '.log';
const logContent = 'Newsletter sent: ' + new Date().toISOString() + '\n' +
  'Type: ' + input.type + '\n' +
  'Subject: ' + input.subject + '\n' +
  'Draft: ' + input.draftPath + '\n' +
  'Recipients: ' + (input.recipients || []).map(function(r) { return r.name + ' <' + r.email + '>'; }).join(', ') + '\n';
fs.mkdirSync('/data/Aidan_Outputs/Sage', { recursive: true });
fs.writeFileSync(logPath, logContent, 'utf8');

// WhatsApp confirmation
const recipientNames = (input.recipients || []).map(function(r) { return r.name; }).join(', ');
let confirmMsg = 'SAGE EMAIL SENT\n\n';
confirmMsg += 'Type: ' + (input.type === 'board' ? 'EAF Board Newsletter' : 'FP Market Newsletter') + '\n';
confirmMsg += 'Subject: ' + input.subject + '\n';
confirmMsg += 'Sent to: ' + recipientNames + '\n';
confirmMsg += 'From: kas@kevin-llc.com\n';
confirmMsg += 'Log: ' + logPath;

const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: confirmMsg } });
const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
await new Promise(function(r) { const req = http.request(opts, function(res) { res.on('data',function(){}); res.on('end',r); }); req.on('error',r); req.write(msgBody); req.end(); });

return [{ json: { success: true, type: input.type, subject: input.subject, recipientCount: input.recipientCount, logPath: logPath } }];
